import subprocess, re

result = subprocess.run(['readelf', '--wide', '-s', 'libmonosgen-2.0.so.dbg'], capture_output=True, text=True)
target1 = 0x2f4b20
target2 = 0x2f4c84

best1 = (0, '', 0)
best2 = (0, '', 0)

for line in result.stdout.splitlines():
    if 'FUNC' not in line:
        continue
    parts = line.split()
    if len(parts) < 8:
        continue
    try:
        addr = int(parts[1], 16)
        size = int(parts[2])
        name = parts[-1]
    except:
        continue
    if addr > 0 and size > 0:
        if addr <= target1 and (addr + size) > target1:
            best1 = (addr, name, size)
        if addr <= target2 and (addr + size) > target2:
            best2 = (addr, name, size)
        # Also track nearest below
        if addr <= target1 and addr > best1[0] and best1[2] == 0:
            pass

print(f'Function containing 0x2f4b20: {best1}')
print(f'Function containing 0x2f4c84: {best2}')

# Also find nearest function below each target
funcs = []
for line in result.stdout.splitlines():
    if 'FUNC' not in line:
        continue
    parts = line.split()
    if len(parts) < 8:
        continue
    try:
        addr = int(parts[1], 16)
        size = int(parts[2])
        name = parts[-1]
        if addr > 0:
            funcs.append((addr, size, name))
    except:
        continue

funcs.sort()
for target, label in [(target1, '0x2f4b20'), (target2, '0x2f4c84')]:
    prev = None
    for addr, size, name in funcs:
        if addr > target:
            break
        prev = (addr, size, name)
    if prev:
        print(f'Nearest FUNC before {label}: 0x{prev[0]:x} size={prev[1]} {prev[2]}')
"

